import type { Ref } from 'react';
import React, { forwardRef } from 'react';
import { useTreeContext } from './hooks/TreeContext';
import type { InternalTreeNodeProps } from './interface';
import { isFunction, logger } from '../util';
import { TreeNodeCheckbox } from './TreeNodeCheckbox';
import { TreeNodeContextProvider } from './hooks/TreeNodeContext';
import { TreeNodeContainer } from './TreeNodeContainer';
import { TreeNodeIndents } from './TreeNodeIndents';
import { TreeNodeCheckmark } from './TreeNodeCheckmark';
import { TreeNodeExpandButton } from './TreeNodeExpandButton';
import { TreeNodeLabel } from './TreeNodeLabel';

// virtual list 需要用到 ref
export const InternalTreeNode = forwardRef((props: InternalTreeNodeProps, ref: Ref<HTMLDivElement>) => {
  const checkboxRef = React.useRef<HTMLInputElement>(null);
  const expandButtonRef = React.useRef<HTMLButtonElement>(null);
  const { doublyTreeNode: node } = props;
  const { nodeRenderer, selectedCache, checkedCache, checkable, expandedMap } = useTreeContext();
  const { value } = node.__node__;

  // ============================= Label =============================

  const isSelected = selectedCache.get(value) ?? false;

  const isChecked = checkedCache.get(value);
  if (isChecked === undefined && checkable) {
    logger.error(`value ${value}, isChecked \`${isChecked}\` is undefined`);
    return null;
  }

  const isExpanded = Boolean(expandedMap[value]);

  const treeNode = (() => {
    if (isFunction(nodeRenderer)) {
      return nodeRenderer(node);
    }
    return (
      <TreeNodeContainer ref={ref}>
        <TreeNodeIndents />
        <TreeNodeExpandButton />
        <TreeNodeCheckbox />
        <TreeNodeLabel />
        <TreeNodeCheckmark />
      </TreeNodeContainer>
    );
  })();

  return (
    <TreeNodeContextProvider
      value={{
        doublyTreeNode: node,
        checkboxRef,
        expandButtonRef,
        isSelected,
        isChecked,
        isExpanded,
      }}
    >
      {treeNode}
    </TreeNodeContextProvider>
  );
});
